require("fs"),async function(){console.log("Fetching products from Firestore...");try{const e=await fetch("https://firestore.googleapis.com/v1/projects/speed-catalogue/databases/(default)/documents/artifacts/speed-catalogue/public/data/products?pageSize=1000"),o=await e.json();if(!o.documents)return void console.error("No products found");console.log("Warming up main home page...");try{await fetch("https://speedgifts.net/"),console.log("Main page warmed up successfully.")}catch(e){console.error("Failed to warm up main page:",e)}console.log("Warming up shop page...");try{await fetch("https://speedgifts.net/shop"),console.log("Shop page warmed up successfully.")}catch(e){console.error("Failed to warm up shop page:",e)}const t=o.documents.map(e=>e.name.split("/").pop()).filter(e=>!["_ad_stats_","--global-stats--","_announcements_","_landing_settings_","_home_settings_","_hero_config_"].includes(e));console.log(`Fetched ${t.length} products to warm up.`);let s=0,a=0;const c=10;for(let e=0;e<t.length;e+=c){const o=t.slice(e,e+c).map(async e=>{const o=`https://speedgifts.net/p/${encodeURIComponent(e)}`;try{(await fetch(o)).ok?s++:a++}catch(e){a++}});await Promise.all(o),await new Promise(e=>setTimeout(e,500)),console.log(`Progress: ${Math.min(e+c,t.length)} / ${t.length}`)}console.log(`Manual Cache warming complete. Success: ${s}, Failed: ${a}`)}catch(e){console.error("Error:",e)}}();